#!/usr/bin/env python3\n\"\"\"\nApply Migration 029: Wallet Funding Denormalization for Whitelist Management\n================================================================================\nAdds denormalized funding columns to wallets table for direct access\nto CEX subaccount and network info.\n\"\"\"\n\nimport sys\nfrom pathlib import Path\n\nsys.path.insert(0, str(Path(__file__).parent))\n\nfrom database.db_manager import DatabaseManager\nfrom loguru import logger\n\ndef main():\n    \"\"\"Apply migration 029.\"\"\"\n    db = DatabaseManager()\n    \n    migration_file = Path(__file__).parent / 'database' / 'migrations' / '029_wallet_funding_denormalization.sql'\n    \n    if not migration_file.exists():\n        logger.error(f\"Migration file not found: {migration_file}\")\n        sys.exit(1)\n    \n    logger.info(f\"Reading migration: {migration_file}\")\n    sql = migration_file.read_text()\n    \n    try:\n        logger.info(\"Executing migration 029...\")\n        db.execute_query(sql)\n        logger.success(\"✅ Migration 029 applied successfully\")\n        \n        # Verify: count wallets with funding info\n        result = db.execute_query(\n            \"SELECT COUNT(*) as count FROM wallets WHERE funding_cex_subaccount_id IS NOT NULL\",\n            fetch='one'\n        )\n        logger.info(f\"Wallets with funding assignment: {result['count']}\")\n        \n        # Distribution by exchange\n        dist = db.execute_query(\n            \"\"\"\n            SELECT cs.exchange, COUNT(*) as wallets_count\n            FROM wallets w\n            JOIN cex_subaccounts cs ON w.funding_cex_subaccount_id = cs.id\n            GROUP BY cs.exchange ORDER BY cs.exchange\n            \"\"\",\n            fetch='all'\n        )\n        logger.info(\"Distribution by exchange:\")\n        for row in dist:\n            logger.info(f\"  {row['exchange']}: {row['wallets_count']} wallets\")\n        \n        # Distribution by network\n        net = db.execute_query(\n            \"SELECT funding_network, COUNT(*) as count FROM wallets WHERE funding_network IS NOT NULL GROUP BY funding_network\",\n            fetch='all'\n        )\n        logger.info(\"Distribution by network:\")\n        for row in net:\n            logger.info(f\"  {row['funding_network']}: {row['count']} wallets\")\n        \n    except Exception as e:\n        logger.error(f\"Migration failed: {e}\")\n        sys.exit(1)\n\nif __name__ == '__main__':\n    main()